60	/*!
61	 * \brief Compute the maximum number of pages per batch and the new batch size
62	 *   after we partition Paged KV-Cache into multiple chunks on KV sequence length
63	 *   dimension.
64	 * \tparam IdType A template type indicates the index data type
65	 * \param max_grid_size The maximum grid size of the kernel
66	 * \param gdy gridDim.y
67	 * \param num_pages The number of pages per request in the batch
68	 * \param max_num_pages_per_batch_lb The pre-set lower bound of maximum number of
69	 *   pages per batch, default to 1
70	 * \return (max_num_pages_per_batch, new_batch_size) The number of pages per batch and
71	 *   the new batch size after the partition.
72	 */
73	template <typename IdType>
74	inline auto PartitionPagedKVCacheBinarySearchMinNumPagePerBatch(
75	    const uint32_t max_grid_size, const uint32_t gdy, const std::vector<IdType>& num_pages,
76	    const uint32_t min_num_pages_per_batch = 1) {
77	  uint32_t low = min_num_pages_per_batch, high = 0;
78	  for (const IdType& elem : num_pages) {
79	    high = max(high, elem);
80	  }
81	  uint32_t new_batch_size;
82	  while (low < high) {
83	    uint32_t mid = (low + high) / 2;
84	    new_batch_size = 0;
85	    for (const IdType& elem : num_pages) {
86	      new_batch_size += ceil_div(elem, mid);
87	    }
88	    if (new_batch_size * gdy > max_grid_size) {
89	      low = mid + 1;
90	    } else {
91	      high = mid;
92	    }
93	  }
94	  new_batch_size = 0;
95	  for (const IdType& elem : num_pages) {
96	    new_batch_size += ceil_div(std::max(elem, 1), low);
97	  }
98	  return std::make_tuple(low, new_batch_size);
99	}
