101	inline auto PrefillBinarySearchKVChunkSize(const bool enable_cuda_graph,
102	                                           const uint32_t max_batch_size_if_split,
103	                                           const std::vector<int64_t>& packed_qo_len_arr,
104	                                           const std::vector<int64_t>& kv_len_arr,
105	                                           const uint32_t qo_chunk_size,
106	                                           const uint32_t min_kv_chunk_size = 1) {
107	  const int64_t batch_size = packed_qo_len_arr.size();
108	  int64_t max_kv_len = 1;
109	  for (const int64_t& kv_len : kv_len_arr) {
110	    max_kv_len = std::max(max_kv_len, kv_len);
111	  }
112	
113	  int64_t low = min_kv_chunk_size;
114	  int64_t high = max_kv_len;
115	  constexpr int64_t min_kv_len = 1;
116	  while (low < high) {
117	    const int64_t mid = (low + high) / 2;
118	    int64_t new_batch_size = 0;
119	    for (uint32_t i = 0; i < batch_size; ++i) {
120	      new_batch_size += ceil_div(packed_qo_len_arr[i], qo_chunk_size) *
121	                        ceil_div(std::max(kv_len_arr[i], min_kv_len), mid);
122	    }
123	    if (new_batch_size > max_batch_size_if_split) {
124	      low = mid + 1;
125	    } else {
126	      high = mid;
127	    }
128	  }
129	  return std::make_tuple(enable_cuda_graph || low < max_kv_len, low);
130	}
