132	/*!
133	 * \brief Estimate the temporary buffer size and the maximum grid size for the
134	 *   partition-kv BatchDecodeWithPagedKVCache kernel
135	 * \tparam DTypeKV A template type indicates the key-value data type
136	 * \tparam DTypeO A template type indicates the output data type
137	 * \tparam IdType A template type indicates the index data type
138	 * \param split_kv Whether to split the KV cache into multiple chunks
139	 * \param max_grid_size The maximum grid size that can be used in a partiton-kv kernel
140	 * \param max_num_pages_per_batch The maximum number of pages per batch
141	 * \param new_batch_size The new batch size after the partition
142	 * \param paged_kv The paged kv cache data structure
143	 * \param num_qo_heads A integer indicates the number of heads of query and output
144	 * \param pos_encoding_mode The positional encoding mode
145	 * \param stream The cuda stream to launch the kernel
146	 * \return status Indicates whether CUDA calls are successful
147	 */
148	template <uint32_t GROUP_SIZE, uint32_t HEAD_DIM, PosEncodingMode POS_ENCODING_MODE,
149	          typename AttentionVariant, typename Params>
150	inline cudaError_t BatchDecodeWithPagedKVCacheWorkEstimationDispatched(
151	    bool& split_kv, uint32_t& max_grid_size, uint32_t& max_num_pages_per_batch,
152	    uint32_t& new_batch_size, uint32_t& gdy, uint32_t batch_size,
153	    typename Params::IdType* kv_indptr_h, const uint32_t num_qo_heads, const uint32_t page_size,
154	    bool enable_cuda_graph, cudaStream_t stream) {
155	  using DTypeKV = typename Params::DTypeKV;
156	  using IdType = typename Params::IdType;
157	  constexpr uint32_t vec_size = std::max(16UL / sizeof(DTypeKV), HEAD_DIM / 32UL);
158	  auto compute_capacity = GetCudaComputeCapability();
159	  DISPATCH_COMPUTE_CAP_DECODE_NUM_STAGES_SMEM(compute_capacity, NUM_STAGES_SMEM, {
160	    constexpr uint32_t bdx = HEAD_DIM / vec_size;
161	    static_assert(bdx <= 32);
162	    constexpr uint32_t bdy = GROUP_SIZE;
163	    constexpr uint32_t num_threads = std::max(128U, bdx * bdy);
164	    constexpr uint32_t bdz = num_threads / (bdx * bdy);
165	    constexpr uint32_t tile_size_per_bdx = GROUP_SIZE == 1 ? (sizeof(DTypeKV) == 1 ? 2U : 4U) : 1U;
166	    const uint32_t num_kv_heads = num_qo_heads / GROUP_SIZE;
167	    gdy = num_kv_heads;
168	    const uint32_t smem_size =
169	        2 * NUM_STAGES_SMEM * tile_size_per_bdx * bdy * bdz * HEAD_DIM * sizeof(DTypeKV) +
170	        std::max(tile_size_per_bdx * num_threads * sizeof(DTypeKV*), 2 * bdy * bdz * sizeof(float));
171	
172	    auto kernel =
173	        BatchDecodeWithPagedKVCacheKernel<POS_ENCODING_MODE, NUM_STAGES_SMEM, tile_size_per_bdx,
174	                                          vec_size, bdx, bdy, bdz, AttentionVariant, Params>;
175	    int num_blocks_per_sm = 0;
176	    int num_sm = 0;
177	    int dev_id = 0;
178	    FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
179	    FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
180	    FLASHINFER_CUDA_CALL(cudaOccupancyMaxActiveBlocksPerMultiprocessor(&num_blocks_per_sm, kernel,
181	                                                                       num_threads, smem_size));
182	    max_grid_size = num_blocks_per_sm * num_sm;
183	    if (batch_size * gdy >= max_grid_size) {
184	      split_kv = false;
185	      max_num_pages_per_batch = 1;
186	      for (uint32_t batch_idx = 0; batch_idx < batch_size; ++batch_idx) {
187	        max_num_pages_per_batch = std::max<uint32_t>(
188	            max_num_pages_per_batch, kv_indptr_h[batch_idx + 1] - kv_indptr_h[batch_idx]);
189	      }
190	      new_batch_size = batch_size;
191	    } else {
192	      // compute max_num_pages_per_batch and new_batch_size
193	      std::vector<IdType> num_pages(batch_size);
194	      for (uint32_t batch_idx = 0; batch_idx < batch_size; ++batch_idx) {
195	        num_pages[batch_idx] = kv_indptr_h[batch_idx + 1] - kv_indptr_h[batch_idx];
196	      }
197	      std::tie(max_num_pages_per_batch, new_batch_size) =
198	          PartitionPagedKVCacheBinarySearchMinNumPagePerBatch(max_grid_size, gdy, num_pages,
199	                                                              std::max(128 / page_size, 1U));
200	      if (new_batch_size == batch_size && !enable_cuda_graph) {
201	        // do not use partition-kv kernel for short sequence, when not using CUDAGraph
202	        split_kv = false;
203	      } else {
204	        // when using CUDAGraph, we always use partition-kv kernel
205	        split_kv = true;
206	      }
207	    }
208	    return cudaSuccess;
209	  })
210	}
