212	template <uint32_t HEAD_DIM_CKV, uint32_t HEAD_DIM_KPE, typename AttentionVariant, typename Params>
213	inline cudaError_t BatchDecodeWithPagedKVCacheWorkEstimationDispatchedMLA(
214	    bool& split_kv, uint32_t& max_grid_size, uint32_t& max_num_pages_per_batch,
215	    uint32_t& new_batch_size, uint32_t& gdy, uint32_t batch_size,
216	    typename Params::IdType* kv_indptr_h, const uint32_t num_qo_heads, const uint32_t page_size,
217	    bool enable_cuda_graph, cudaStream_t stream) {
218	  using DTypeKV = typename Params::DTypeKV;
219	  using IdType = typename Params::IdType;
220	
221	  auto compute_capacity = GetCudaComputeCapability();
222	  DISPATCH_COMPUTE_CAP_DECODE_NUM_STAGES_SMEM(compute_capacity, NUM_STAGES_SMEM, {
223	    constexpr uint32_t vec_size_ckv = std::max(16UL / sizeof(DTypeKV), HEAD_DIM_CKV / 32UL);
224	    constexpr uint32_t bdx = HEAD_DIM_CKV / vec_size_ckv;
225	    constexpr uint32_t vec_size_kpe = HEAD_DIM_KPE / bdx;
226	
227	    constexpr uint32_t bdy = 8;
228	    constexpr uint32_t tile_size_qo_heads = 2;
229	    constexpr uint32_t qo_heads_per_block = bdy * tile_size_qo_heads;
230	    constexpr uint32_t num_threads = std::max(128U, bdx * bdy);
231	    constexpr uint32_t bdz = num_threads / (bdx * bdy);
232	    gdy = ceil_div(num_qo_heads, qo_heads_per_block);
233	
234	    const uint32_t smem_size =
235	        NUM_STAGES_SMEM * bdy * bdz * (HEAD_DIM_CKV + HEAD_DIM_KPE) * sizeof(DTypeKV) +
236	        std::max(num_threads * sizeof(size_t) * 2, 2 * bdy * bdz * sizeof(float));
237	
238	    auto kernel =
239	        BatchDecodeWithPagedKVCacheKernelMLA<NUM_STAGES_SMEM, vec_size_ckv, vec_size_kpe, bdx, bdy,
240	                                             bdz, tile_size_qo_heads, AttentionVariant, Params>;
241	    int num_blocks_per_sm = 0;
242	    int num_sm = 0;
243	    int dev_id = 0;
244	    FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
245	    FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
246	    FLASHINFER_CUDA_CALL(cudaOccupancyMaxActiveBlocksPerMultiprocessor(&num_blocks_per_sm, kernel,
247	                                                                       num_threads, smem_size));
248	    max_grid_size = num_blocks_per_sm * num_sm;
249	    if (batch_size * gdy >= max_grid_size) {
250	      split_kv = false;
251	      max_num_pages_per_batch = 1;
252	      for (uint32_t batch_idx = 0; batch_idx < batch_size; ++batch_idx) {
253	        max_num_pages_per_batch = std::max<uint32_t>(
254	            max_num_pages_per_batch, kv_indptr_h[batch_idx + 1] - kv_indptr_h[batch_idx]);
255	      }
256	      new_batch_size = batch_size;
257	    } else {
258	      // compute max_num_pages_per_batch and new_batch_size
259	      std::vector<IdType> num_pages(batch_size);
260	      for (uint32_t batch_idx = 0; batch_idx < batch_size; ++batch_idx) {
261	        num_pages[batch_idx] = kv_indptr_h[batch_idx + 1] - kv_indptr_h[batch_idx];
262	      }
263	      std::tie(max_num_pages_per_batch, new_batch_size) =
264	          PartitionPagedKVCacheBinarySearchMinNumPagePerBatch(max_grid_size, gdy, num_pages,
265	                                                              std::max(128 / page_size, 1U));
266	      if (new_batch_size == batch_size && !enable_cuda_graph) {
267	        // do not use partition-kv kernel for short sequence, when not using CUDAGraph
268	        split_kv = false;
269	      } else {
270	        // when using CUDAGraph, we always use partition-kv kernel
271	        split_kv = true;
272	      }
273	    }
274	
275	    return cudaSuccess;
276	  });
277	}
