279	template <uint32_t HEAD_DIM_CKV, uint32_t HEAD_DIM_KPE, uint32_t QO_TILE_LEN,
280	          typename AttentionVariant, typename Params>
281	inline cudaError_t BatchDecodeWithPagedKVCacheWorkEstimationDispatchedMlaCuteSM80(
282	    bool& split_kv, uint32_t& max_grid_size, uint32_t& max_num_pages_per_batch,
283	    uint32_t& new_batch_size, uint32_t& gdy_, uint32_t batch_size,
284	    typename Params::IdType* kv_indptr_h, const uint32_t num_qo_heads, const uint32_t page_size,
285	    bool enable_cuda_graph, cudaStream_t stream) {
286	  using DTypeKV = typename Params::DTypeKV;
287	  using IdType = typename Params::IdType;
288	
289	  auto [smem_size, gdy, k_warps] =
290	      LaunchSpecForDecodeKernelMlaCuteSM80<HEAD_DIM_CKV, HEAD_DIM_KPE, QO_TILE_LEN, DTypeKV>(
291	          num_qo_heads);
292	  gdy_ = gdy;
293	  const uint32_t num_threads = k_warps * 32;
294	  auto kernel =
295	      BatchDecodeWithPagedKVCacheKernelMlaCuteSM80<HEAD_DIM_CKV, HEAD_DIM_KPE, QO_TILE_LEN, Params>;
296	  int num_blocks_per_sm;
297	  int num_sm = 0;
298	  int dev_id = 0;
299	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
300	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
301	
302	  // FLASHINFER_CUDA_CALL(cudaOccupancyMaxActiveBlocksPerMultiprocessor(&num_blocks_per_sm, kernel,
303	  //                                   num_threads, smem_size));
304	  // fixme: num_blocks_per_sm is 0 derived from cudaOccupancyMaxActiveBlocksPerMultiprocessor at
305	  // times, and we fill smem with q-heads as many as possible, so num_blocks_per_sm should be 1
306	  num_blocks_per_sm = 1;
307	
308	  max_grid_size = num_blocks_per_sm * num_sm;
309	  if (batch_size * gdy >= max_grid_size) {
310	    split_kv = false;
311	    max_num_pages_per_batch = 1;
312	    for (uint32_t batch_idx = 0; batch_idx < batch_size; ++batch_idx) {
313	      max_num_pages_per_batch = std::max<uint32_t>(
314	          max_num_pages_per_batch, kv_indptr_h[batch_idx + 1] - kv_indptr_h[batch_idx]);
315	    }
316	    new_batch_size = batch_size;
317	  } else {
318	    // compute max_num_pages_per_batch and new_batch_size
319	    std::vector<IdType> num_pages(batch_size);
320	    for (uint32_t batch_idx = 0; batch_idx < batch_size; ++batch_idx) {
321	      num_pages[batch_idx] = kv_indptr_h[batch_idx + 1] - kv_indptr_h[batch_idx];
322	    }
323	    std::tie(max_num_pages_per_batch, new_batch_size) =
324	        PartitionPagedKVCacheBinarySearchMinNumPagePerBatch(max_grid_size, gdy, num_pages,
325	                                                            std::max(128 / page_size, 1U));
326	    if (new_batch_size == batch_size && !enable_cuda_graph) {
327	      // do not use partition-kv kernel for short sequence, when not using CUDAGraph
328	      split_kv = false;
329	    } else {
330	      // when using CUDAGraph, we always use partition-kv kernel
331	      split_kv = true;
332	    }
333	  }
334	
335	  return cudaSuccess;
336	}
