378	  DecodePlanInfo()
379	      : padded_batch_size(0),
380	        v_offset(0),
381	        s_offset(0),
382	        request_indices_offset(0),
383	        kv_tile_indices_offset(0),
384	        o_indptr_offset(0),
385	        block_valid_mask_offset(0),
386	        kv_chunk_size_ptr_offset(0),
387	        enable_cuda_graph(false),
388	        split_kv(false) {}
389	
390	  // convert DecodePlanInfo to std::vector<int64_t>
391	  std::vector<int64_t> ToVector() const {
392	    return {padded_batch_size,
393	            v_offset,
