404	  // From std::vector<int64_t> to DecodePlanInfo
405	  void FromVector(const std::vector<int64_t>& vec) {
406	    if (vec.size() != 10) {
407	      std::ostringstream err_msg;
408	      err_msg << "DecodePlanInfo::FromVector: vec.size() should be 10, but got " << vec.size();
409	      FLASHINFER_ERROR(err_msg.str());
410	    }
411	    padded_batch_size = vec[0];
412	    v_offset = vec[1];
413	    s_offset = vec[2];
414	    request_indices_offset = vec[3];
415	    kv_tile_indices_offset = vec[4];
416	    o_indptr_offset = vec[5];
417	    block_valid_mask_offset = vec[6];
418	    kv_chunk_size_ptr_offset = vec[7];
419	    enable_cuda_graph = vec[8];
420	    split_kv = vec[9];
421	  }
422	};
