424	template <bool MATERIALIZE, uint32_t HEAD_DIM, PosEncodingMode POS_ENCODING_MODE,
425	          typename AttentionVariant, typename Params, typename WorkEstimationFunc>
426	inline cudaError_t DecodePlanImpl(size_t& float_workspace_size_out, size_t& int_workspace_size_out,
427	                                  void* float_buffer, size_t float_workspace_size_in_bytes,
428	                                  void* int_buffer, void* page_locked_int_buffer,
429	                                  size_t int_workspace_size_in_bytes, DecodePlanInfo& plan_info,
430	                                  typename Params::IdType* indptr_h, uint32_t batch_size,
431	                                  uint32_t num_qo_heads, uint32_t page_size, bool enable_cuda_graph,
432	                                  cudaStream_t stream, WorkEstimationFunc work_estimation_func) {
433	  using IdType = typename Params::IdType;
434	  bool split_kv;
435	  uint32_t max_grid_size, kv_chunk_size_in_pages, new_batch_size, gdy;
436	
437	  FLASHINFER_CUDA_CALL(work_estimation_func(split_kv, max_grid_size, kv_chunk_size_in_pages,
438	                                            new_batch_size, gdy, batch_size, indptr_h, num_qo_heads,
439	                                            page_size, enable_cuda_graph, stream));
440	  size_t padded_batch_size;
441	  plan_info.enable_cuda_graph = enable_cuda_graph;
442	  plan_info.split_kv = split_kv;
443	  padded_batch_size =
444	      (enable_cuda_graph) ? (split_kv ? max_grid_size / gdy : batch_size) : new_batch_size;
445	  plan_info.padded_batch_size = padded_batch_size;
446	  auto [request_indices_vec, kv_tile_indices_vec, o_indptr_vec] =
447	      DecodeSplitKVIndptr(indptr_h, batch_size, kv_chunk_size_in_pages);
448	
449	  AlignedAllocator int_allocator =
450	      MATERIALIZE ? AlignedAllocator(int_buffer, int_workspace_size_in_bytes) : AlignedAllocator();
451	  plan_info.request_indices_offset = int_allocator.aligned_alloc_offset(
452	      padded_batch_size * sizeof(IdType), 16, "batch_decode_request_indices");
453	  plan_info.kv_tile_indices_offset = int_allocator.aligned_alloc_offset(
454	      padded_batch_size * sizeof(IdType), 16, "batch_decode_kv_tile_indices");
455	  plan_info.o_indptr_offset = int_allocator.aligned_alloc_offset(
456	      (padded_batch_size + 1) * sizeof(IdType), 16, "batch_decode_o_indptr");
457	  plan_info.kv_chunk_size_ptr_offset =
458	      int_allocator.aligned_alloc_offset(sizeof(IdType), 1, "batch_decode_kv_chunk_size_ptr");
459	  if constexpr (MATERIALIZE) {
460	    IdType* request_indices_h =
461	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.request_indices_offset);
462	    IdType* kv_tile_indices_h =
463	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_tile_indices_offset);
464	    IdType* o_indptr_h =
465	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.o_indptr_offset);
466	    IdType* kv_chunk_size_ptr_h =
467	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_chunk_size_ptr_offset);
468	    std::copy(request_indices_vec.begin(), request_indices_vec.end(), request_indices_h);
469	    std::copy(kv_tile_indices_vec.begin(), kv_tile_indices_vec.end(), kv_tile_indices_h);
470	    std::copy(o_indptr_vec.begin(), o_indptr_vec.end(), o_indptr_h);
471	    kv_chunk_size_ptr_h[0] = kv_chunk_size_in_pages * page_size;
472	  } else {
473	    (void)kv_chunk_size_in_pages;
474	    (void)new_batch_size;
475	    (void)request_indices_vec;
476	    (void)kv_tile_indices_vec;
477	    (void)o_indptr_vec;
478	  }
479	
480	  AlignedAllocator float_allocator;
481	  if (split_kv) {
482	    if constexpr (MATERIALIZE) {
483	      float_allocator = AlignedAllocator(float_buffer, float_workspace_size_in_bytes);
484	    }
485	    plan_info.v_offset = float_allocator.aligned_alloc_offset(
486	        num_qo_heads * padded_batch_size * HEAD_DIM * sizeof(float), 16, "batch_decode_tmp_v");
487	    plan_info.s_offset = float_allocator.aligned_alloc_offset(
488	        num_qo_heads * padded_batch_size * sizeof(float), 16, "batch_decode_tmp_s");
489	
490	    plan_info.block_valid_mask_offset = int_allocator.aligned_alloc_offset(
491	        padded_batch_size * sizeof(bool), 16, "batch_decode_block_valid_mask");
492	    if constexpr (MATERIALIZE) {
493	      bool* block_valid_mask_h =
494	          GetPtrFromBaseOffset<bool>(page_locked_int_buffer, plan_info.block_valid_mask_offset);
495	      for (uint32_t i = 0; i < padded_batch_size; ++i) {
496	        block_valid_mask_h[i] = i < new_batch_size;
497	      }
498	    }
499	  }
500	
501	  float_workspace_size_out = float_allocator.num_allocated_bytes();
502	  int_workspace_size_out = int_allocator.num_allocated_bytes();
503	  if constexpr (MATERIALIZE) {
504	    FLASHINFER_CUDA_CALL(cudaMemcpyAsync(int_buffer, page_locked_int_buffer, int_workspace_size_out,
505	                                         cudaMemcpyHostToDevice, stream));
506	  }
507	  return cudaSuccess;
508	}
