544	template <typename IdType>
545	inline auto PrefillSplitQOKVIndptr(IdType* qo_indptr_h, IdType* kv_indptr_h,
546	                                   uint32_t total_num_rows, uint32_t batch_size,
547	                                   uint32_t num_qo_heads, uint32_t num_kv_heads, uint32_t head_dim,
548	                                   uint32_t page_size, uint32_t max_batch_size_if_split,
549	                                   bool enable_cuda_graph, int32_t window_left,
550	                                   int32_t fixed_split_size, bool disable_split_kv) {
551	  std::vector<IdType> request_indices, qo_tile_indices, kv_tile_indices, merge_indptr, o_indptr;
552	  merge_indptr.push_back(0);
553	  o_indptr.push_back(0);
554	
555	  const uint32_t gqa_group_size = num_qo_heads / num_kv_heads;
556	
557	  // step 1: determine packed_qo_len_arr and verify qo_indptr contents.
558	  std::vector<int64_t> packed_qo_len_arr(batch_size), kv_len_arr(batch_size);
559	  for (uint32_t i = 0; i < batch_size; ++i) {
560	    packed_qo_len_arr[i] = int64_t(qo_indptr_h[i + 1] - qo_indptr_h[i]) * int64_t(gqa_group_size);
561	    if (packed_qo_len_arr[i] < 0) {
562	      std::ostringstream err_msg;
563	      err_msg << "qo_indptr[" << i + 1 << "]" << qo_indptr_h[i + 1] << " - qo_indptr[" << i << "]"
564	              << qo_indptr_h[i] << " should be non-negative";
565	      FLASHINFER_ERROR(err_msg.str());
566	    }
567	    kv_len_arr[i] = int64_t(kv_indptr_h[i + 1] - kv_indptr_h[i]);
568	    if (kv_len_arr[i] < 0) {
569	      std::ostringstream err_msg;
570	      err_msg << "kv_indptr[" << i + 1 << "]" << kv_indptr_h[i + 1] << " - kv_indptr[" << i << "]"
571	              << kv_indptr_h[i] << " should be non-negative";
572	      FLASHINFER_ERROR(err_msg.str());
573	    }
574	  }
575	
576	  // step 2: determine cta_tile_q, kv_chunk_size and total_num_tiles_q
577	  const uint32_t min_kv_chunk_size = std::max((128 / page_size), 1U);
578	  uint32_t cta_tile_q;
579	  uint32_t total_num_tiles_q;
580	  if (enable_cuda_graph) {
581	    // When CUDA graphs are enabled, the lengths of sequences determined by
582	    // qo_indptr_h can vary. We assume that the dummy data based on which
583	    // the CUDA graph is created fixes the maximum number of tokens.
584	    const uint64_t max_seq_len = total_num_rows - batch_size + 1;
585	    uint64_t max_qo_len = uint64_t(max_seq_len) * gqa_group_size;
586	    cta_tile_q = FA2DetermineCtaTileQ(max_qo_len, head_dim);
587	
588	    // Find an upper bound for the number of tiles, derived from the total
589	    // number of rows and the batch size.  The sum of qo lengths rounded
590	    // up to cta_tile_q will not exceed this number derived from the total
591	    // number of rows.
592	    total_num_tiles_q = ceil_div(total_num_rows * gqa_group_size, cta_tile_q) + batch_size - 1;
593	  } else {
594	    int64_t sum_packed_qo_len = 0;
595	    for (uint32_t i = 0; i < batch_size; ++i) {
596	      sum_packed_qo_len += packed_qo_len_arr[i];
597	    }
598	    const int64_t avg_packed_qo_len = sum_packed_qo_len / batch_size;
599	    cta_tile_q = FA2DetermineCtaTileQ(avg_packed_qo_len, head_dim);
600	
601	    total_num_tiles_q = 0;
602	    for (uint32_t i = 0; i < batch_size; ++i) {
603	      total_num_tiles_q += ceil_div(packed_qo_len_arr[i], cta_tile_q);
604	    }
605	  }
606	
607	  // Calculate the actual needed CTA when considering sliding window
608	  std::vector<int64_t> effective_kv_len_arr(batch_size);
609	  for (uint32_t i = 0; i < batch_size; ++i) {
610	    // pad CTA_TILE_Q to consider the causal kv-len
611	    effective_kv_len_arr[i] =
612	        std::min(window_left >= 0 ? ceil_div(window_left + cta_tile_q, page_size) : kv_len_arr[i],
613	                 kv_len_arr[i]);
614	  }
615	  bool split_kv = false;
616	  int64_t kv_chunk_size;
617	  if (disable_split_kv) {
618	    kv_chunk_size = std::numeric_limits<int64_t>::max();
619	  } else if (!disable_split_kv && fixed_split_size > 0) {
620	    kv_chunk_size = fixed_split_size;
621	  } else {
622	    std::tie(split_kv, kv_chunk_size) = PrefillBinarySearchKVChunkSize(
623	        enable_cuda_graph, max_batch_size_if_split, packed_qo_len_arr, effective_kv_len_arr,
624	        cta_tile_q, min_kv_chunk_size);
625	  }
626	  // step 3: split qo_indptr and kv_indptr
627	  uint32_t new_batch_size = 0;
628	  for (uint32_t request_idx = 0; request_idx < batch_size; ++request_idx) {
629	    const int64_t packed_qo_len = packed_qo_len_arr[request_idx];
630	    const int64_t num_tiles_q = ceil_div(packed_qo_len, cta_tile_q);
631	    const int64_t kv_len = std::max(int(effective_kv_len_arr[request_idx]), 1);
632	    const int64_t num_chunks_kv = disable_split_kv ? 1 : ceil_div(kv_len, kv_chunk_size);
633	    if (fixed_split_size > 0 && !disable_split_kv) {
634	      split_kv = split_kv || num_chunks_kv > 1;
635	    }
636	    for (uint32_t q_tile_idx = 0; q_tile_idx < num_tiles_q; ++q_tile_idx) {
637	      for (uint32_t kv_tile_idx = 0; kv_tile_idx < num_chunks_kv; ++kv_tile_idx) {
638	        new_batch_size += 1;
639	        request_indices.push_back(request_idx);
640	        qo_tile_indices.push_back(q_tile_idx);
641	        kv_tile_indices.push_back(kv_tile_idx);
642	      }
643	    }
644	
645	    int64_t qo_len = packed_qo_len / gqa_group_size;
646	    for (uint32_t row = 0; row < qo_len; ++row) {
647	      merge_indptr.push_back(merge_indptr.back() + num_chunks_kv);
648	    }
649	    o_indptr.push_back(o_indptr.back() + qo_len * num_chunks_kv);
650	  }
651	
652	  const size_t padded_batch_size =
653	      enable_cuda_graph ? std::max(max_batch_size_if_split, total_num_tiles_q) : new_batch_size;
654	  FLASHINFER_CHECK(new_batch_size <= padded_batch_size,
655	                   "new batch size should not exceed padded batch size. If you are using fixed "
656	                   "split size, please consider disabling cuda graph.");
657	
658	  // step 4: multiply kv_chunk_size by page_size
659	  kv_chunk_size *= page_size;
660	  return std::make_tuple(split_kv, new_batch_size, padded_batch_size, cta_tile_q, kv_chunk_size,
661	                         std::move(request_indices), std::move(qo_tile_indices),
662	                         std::move(kv_tile_indices), std::move(merge_indptr), std::move(o_indptr));
663	}
