668	  int64_t total_num_rows_offset;
669	  int64_t cta_tile_q;
670	  int64_t request_indices_offset;
671	  int64_t qo_tile_indices_offset;
672	  int64_t kv_tile_indices_offset;
673	  int64_t merge_indptr_offset;
674	  int64_t o_indptr_offset;
675	  int64_t kv_chunk_size_ptr_offset;
676	  int64_t v_offset;
677	  int64_t s_offset;
678	  int64_t block_valid_mask_offset;
679	  bool enable_cuda_graph;
680	  bool split_kv;
681	
682	  PrefillPlanInfo()
683	      : padded_batch_size(0),
684	        total_num_rows(0),
685	        total_num_rows_offset(0),
686	        cta_tile_q(0),
687	        request_indices_offset(0),
688	        qo_tile_indices_offset(0),
689	        kv_tile_indices_offset(0),
690	        merge_indptr_offset(0),
691	        o_indptr_offset(0),
692	        kv_chunk_size_ptr_offset(0),
693	        v_offset(0),
694	        s_offset(0),
695	        block_valid_mask_offset(0),
696	        enable_cuda_graph(false),
697	        split_kv(false) {}
698	
699	  // convert PrefillPlanInfo to std::vector<int64_t>
700	  std::vector<int64_t> ToVector() const {
701	    return {padded_batch_size,
702	            total_num_rows,
703	            total_num_rows_offset,
704	            cta_tile_q,
705	            request_indices_offset,
706	            qo_tile_indices_offset,
707	            kv_tile_indices_offset,
708	            merge_indptr_offset,
709	            o_indptr_offset,
710	            kv_chunk_size_ptr_offset,
711	            v_offset,
712	            s_offset,
713	            block_valid_mask_offset,
714	            enable_cuda_graph,
