716	  }
717	
718	  // From std::vector<int64_t> to PrefillPlanInfo
719	  void FromVector(const std::vector<int64_t>& vec) {
720	    if (vec.size() != 15) {
721	      std::ostringstream err_msg;
722	      err_msg << "PrefillPlanInfo::FromVector: vec.size() should be 15, but got " << vec.size();
723	      FLASHINFER_ERROR(err_msg.str());
724	    }
725	    padded_batch_size = vec[0];
726	    total_num_rows = vec[1];
727	    total_num_rows_offset = vec[2];
728	    cta_tile_q = vec[3];
729	    request_indices_offset = vec[4];
730	    qo_tile_indices_offset = vec[5];
731	    kv_tile_indices_offset = vec[6];
732	    merge_indptr_offset = vec[7];
733	    o_indptr_offset = vec[8];
734	    kv_chunk_size_ptr_offset = vec[9];
735	    v_offset = vec[10];
736	    s_offset = vec[11];
737	    block_valid_mask_offset = vec[12];
738	    enable_cuda_graph = vec[13];
739	    split_kv = vec[14];
740	  }
741	};
