743	template <bool MATERIALIZE, typename IdType>
744	inline cudaError_t PrefillPlanImpl(
745	    size_t& float_workspace_size_out, size_t& int_workspace_size_out, void* float_buffer,
746	    size_t float_workspace_size_in_bytes, void* int_buffer, void* page_locked_int_buffer,
747	    size_t int_workspace_size_in_bytes, PrefillPlanInfo& plan_info, IdType* qo_indptr_h,
748	    IdType* kv_indptr_h, uint32_t total_num_rows, uint32_t batch_size, uint32_t num_qo_heads,
749	    uint32_t num_kv_heads, uint32_t head_dim_qk, uint32_t head_dim_vo, uint32_t page_size,
750	    bool enable_cuda_graph, uint32_t sizeof_dtype_o, int32_t window_left, int32_t fixed_split_size,
751	    bool disable_split_kv,
752	    int64_t num_colocated_ctas,  // for POD attention, limit prefill
753	                                 // splits by #colocated decode CTAs
754	    cudaStream_t stream) {
755	  (void)head_dim_qk;
756	  (void)sizeof_dtype_o;
757	  if (num_qo_heads % num_kv_heads != 0) {
758	    std::ostringstream err_msg;
759	    err_msg << "num_qo_heads " << num_qo_heads << " should be divisible by num_kv_heads "
760	            << num_kv_heads;
761	    FLASHINFER_ERROR(err_msg.str());
762	  }
763	
764	  // step 0: get the number of SMs
765	  int num_sm = 0;
766	  int dev_id = 0;
767	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
768	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
769	  int num_blocks_per_sm = 2;
770	  int64_t available_ctas = static_cast<int64_t>(num_blocks_per_sm) * num_sm - num_colocated_ctas;
771	  int max_grid_size = static_cast<int>(std::max<int64_t>(0, available_ctas));
772	  uint32_t max_batch_size_if_split = max_grid_size / num_kv_heads;
773	
774	  // step 2: determine kv_chunk_size
775	  auto [split_kv, new_batch_size, padded_batch_size, cta_tile_q, kv_chunk_size, request_indices_vec,
776	        qo_tile_indices_vec, kv_tile_indices_vec, merge_indptr_vec, o_indptr_vec] =
777	      PrefillSplitQOKVIndptr(qo_indptr_h, kv_indptr_h, total_num_rows, batch_size, num_qo_heads,
778	                             num_kv_heads, head_dim_vo, page_size, max_batch_size_if_split,
779	                             enable_cuda_graph, window_left, fixed_split_size, disable_split_kv);
780	
781	  plan_info.cta_tile_q = cta_tile_q;
782	  plan_info.total_num_rows = total_num_rows;
783	  plan_info.enable_cuda_graph = enable_cuda_graph;
784	  plan_info.padded_batch_size = padded_batch_size;
785	  plan_info.split_kv = split_kv;
786	
787	  AlignedAllocator int_allocator =
788	      MATERIALIZE ? AlignedAllocator(int_buffer, int_workspace_size_in_bytes) : AlignedAllocator();
789	  plan_info.request_indices_offset = int_allocator.aligned_alloc_offset(
790	      sizeof(IdType) * padded_batch_size, 16, "batch_prefill_request_indices");
791	  plan_info.qo_tile_indices_offset = int_allocator.aligned_alloc_offset(
792	      sizeof(IdType) * padded_batch_size, 16, "batch_prefill_qo_tile_indices");
793	  plan_info.kv_tile_indices_offset = int_allocator.aligned_alloc_offset(
794	      sizeof(IdType) * padded_batch_size, 16, "batch_prefill_kv_tile_indices");
795	  plan_info.o_indptr_offset = int_allocator.aligned_alloc_offset(sizeof(IdType) * (batch_size + 1),
796	                                                                 16, "batch_prefill_o_indptr");
797	  plan_info.kv_chunk_size_ptr_offset =
798	      int_allocator.aligned_alloc_offset(sizeof(IdType), 1, "batch_prefill_kv_chunk_size_ptr");
799	
800	  if (plan_info.enable_cuda_graph) {
801	    plan_info.total_num_rows_offset =
802	        int_allocator.aligned_alloc_offset(sizeof(uint32_t), 16, "batch_prefill_total_num_rows");
803	    if constexpr (MATERIALIZE) {
804	      uint32_t* total_num_rows_h =
805	          GetPtrFromBaseOffset<uint32_t>(page_locked_int_buffer, plan_info.total_num_rows_offset);
806	      *total_num_rows_h = qo_indptr_h[batch_size];
807	    }
808	  }
809	
810	  if constexpr (MATERIALIZE) {
811	    IdType* request_indices_h =
812	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.request_indices_offset);
813	    IdType* qo_tile_indices_h =
814	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.qo_tile_indices_offset);
815	    IdType* kv_tile_indices_h =
816	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_tile_indices_offset);
817	    IdType* o_indptr_h =
818	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.o_indptr_offset);
819	    IdType* kv_chunk_size_ptr_h =
820	        GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_chunk_size_ptr_offset);
821	    std::copy(request_indices_vec.begin(), request_indices_vec.end(), request_indices_h);
822	    std::copy(qo_tile_indices_vec.begin(), qo_tile_indices_vec.end(), qo_tile_indices_h);
823	    std::copy(kv_tile_indices_vec.begin(), kv_tile_indices_vec.end(), kv_tile_indices_h);
824	    std::copy(o_indptr_vec.begin(), o_indptr_vec.end(), o_indptr_h);
825	    kv_chunk_size_ptr_h[0] = kv_chunk_size;
826	  } else {
827	    (void)new_batch_size;
828	    (void)kv_chunk_size;
829	    (void)request_indices_vec;
830	    (void)qo_tile_indices_vec;
831	    (void)kv_tile_indices_vec;
832	    (void)o_indptr_vec;
833	  }
834	
835	  AlignedAllocator float_allocator;
836	  if (split_kv) {
837	    if constexpr (MATERIALIZE) {
838	      float_allocator = AlignedAllocator(float_buffer, float_workspace_size_in_bytes);
839	    }
840	    plan_info.v_offset = float_allocator.aligned_alloc_offset(
841	        num_qo_heads * padded_batch_size * cta_tile_q * head_dim_vo * sizeof(float), 16,
842	        "batch_prefill_tmp_v");
843	    plan_info.s_offset = float_allocator.aligned_alloc_offset(
844	        num_qo_heads * padded_batch_size * cta_tile_q * sizeof(float), 16, "batch_prefill_tmp_s");
845	    plan_info.merge_indptr_offset = int_allocator.aligned_alloc_offset(
846	        sizeof(IdType) * (plan_info.total_num_rows + 1), 16, "batch_prefill_merge_indptr");
847	    plan_info.block_valid_mask_offset = int_allocator.aligned_alloc_offset(
848	        sizeof(bool) * padded_batch_size, 16, "batch_prefill_block_valid_mask");
849	
850	    if constexpr (MATERIALIZE) {
851	      IdType* merge_indptr_h =
852	          GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.merge_indptr_offset);
853	      bool* block_valid_mask_h =
854	          GetPtrFromBaseOffset<bool>(page_locked_int_buffer, plan_info.block_valid_mask_offset);
855	      std::copy(merge_indptr_vec.begin(), merge_indptr_vec.end(), merge_indptr_h);
856	      for (uint32_t i = 0; i < padded_batch_size; ++i) {
857	        block_valid_mask_h[i] = i < new_batch_size;
858	      }
859	    } else {
860	      (void)merge_indptr_vec;
861	    }
862	  }
863	
864	  float_workspace_size_out = float_allocator.num_allocated_bytes();
865	  int_workspace_size_out = int_allocator.num_allocated_bytes();
866	  if constexpr (MATERIALIZE) {
867	    FLASHINFER_CUDA_CALL(cudaMemcpyAsync(int_buffer, page_locked_int_buffer, int_workspace_size_out,
868	                                         cudaMemcpyHostToDevice, stream));
869	  } else {
870	    (void)stream;
871	  }
872	
873	  return cudaSuccess;
874	}
