918	template <typename T>
919	std::vector<T> flatten(const std::vector<std::vector<T>>& vec, int size_after_flatten) {
920	  std::vector<T> result;
921	  result.reserve(size_after_flatten);
922	  for (const auto& inner_vec : vec) {
923	    result.insert(result.end(), inner_vec.begin(), inner_vec.end());
924	  }
925	  return result;
926	}
