928	inline int packed_causal_kv_end(int qo_len, int kv_len, int qo_tile_idx, int cluster_tile_q,
929	                                int num_qo_tiles, int group_size) {
930	  if (qo_tile_idx + 1 == num_qo_tiles) {
931	    return kv_len;
932	  }
933	  int kv_len_init = kv_len - qo_len;  // right aligned
934	  return max(min(kv_len_init + ceil_div((qo_tile_idx + 1) * cluster_tile_q, group_size), kv_len),
935	             0);
936	}
