986	template <typename IdType>
987	inline cudaError_t PrefillSM90Plan(
988	    void* float_buffer, size_t float_workspace_size_in_bytes, void* int_buffer,
989	    void* page_locked_int_buffer, size_t int_workspace_size_in_bytes,
990	    PrefillPlanSM90Info& plan_info, IdType* qo_indptr_h, IdType* kv_indptr_h, IdType* kv_len_arr_h,
991	    uint32_t total_num_rows, uint32_t batch_size, uint32_t num_qo_heads, uint32_t num_kv_heads,
992	    uint32_t head_dim_qk, uint32_t head_dim_vo, uint32_t page_size, bool causal,
993	    bool enable_cuda_graph, uint32_t sizeof_dtype_o, cudaStream_t stream) {
994	  if (num_qo_heads % num_kv_heads != 0) {
995	    std::ostringstream err_msg;
996	    err_msg << "num_qo_heads " << num_qo_heads << " should be divisible by num_kv_heads "
997	            << num_kv_heads;
998	    FLASHINFER_ERROR(err_msg.str());
999	  }
1000	
1001	  std::vector<std::tuple<int, int, int>> idx_qo_kv_len_vec;
1002	  for (uint32_t i = 0; i < batch_size; ++i) {
1003	    int qo_len = qo_indptr_h[i + 1] - qo_indptr_h[i];
1004	    int kv_len = kv_len_arr_h[i];
1005	    if (kv_len < 0) {
1006	      std::ostringstream err_msg;
1007	      err_msg << "kv_len[" << i << "]" << kv_len << " should be non-negative";
1008	      FLASHINFER_ERROR(err_msg.str());
1009	    }
1010	    if (qo_len < 0) {
1011	      std::ostringstream err_msg;
1012	      err_msg << "qo_indptr[" << i + 1 << "]" << qo_indptr_h[i + 1] << " - qo_indptr[" << i << "]"
1013	              << qo_indptr_h[i] << " should be non-negative";
1014	      FLASHINFER_ERROR(err_msg.str());
1015	    }
1016	    idx_qo_kv_len_vec.push_back({i, qo_len, kv_len});
1017	  }
1018	
1019	  std::sort(idx_qo_kv_len_vec.begin(), idx_qo_kv_len_vec.end(),
1020	            [](const auto& a, const auto& b) { return std::get<2>(a) > std::get<2>(b); });
1021	  int cta_tile_q = 128;
1022	  if (head_dim_vo == 64) {
1023	    cta_tile_q = 192;
1024	  }
1025	
1026	  int device = 0;
1027	  FLASHINFER_CUDA_CALL(cudaGetDevice(&device));
1028	  int num_sm90_ctas = 0;
1029	  FLASHINFER_CUDA_CALL(
1030	      cudaDeviceGetAttribute(&num_sm90_ctas, cudaDevAttrMultiProcessorCount, device));
1031	
1032	  MinHeap cta_cost_heap(num_sm90_ctas);
1033	  std::vector<std::vector<IdType>> cta_qo_tile_indices(num_sm90_ctas, std::vector<IdType>()),
1034	      cta_qo_indptr(num_sm90_ctas, std::vector<IdType>()),
1035	      cta_kv_indptr(num_sm90_ctas, std::vector<IdType>()),
1036	      cta_qo_len(num_sm90_ctas, std::vector<IdType>()),
1037	      cta_kv_len(num_sm90_ctas, std::vector<IdType>()),
1038	      cta_head_indices(num_sm90_ctas, std::vector<IdType>()),
1039	      cta_batch_indices(num_sm90_ctas, std::vector<IdType>());
1040	
1041	  int max_num_works_per_head = ceil_div(total_num_rows, cta_tile_q) + batch_size - 1;
1042	  plan_info.same_schedule_for_all_heads = max_num_works_per_head > 4096;
1043	
1044	  for (int qo_head_idx = 0;
1045	       qo_head_idx < (plan_info.same_schedule_for_all_heads ? 1 : num_qo_heads); ++qo_head_idx) {
1046	    for (auto& [i, qo_len, kv_len] : idx_qo_kv_len_vec) {
1047	      int num_qo_tiles = ceil_div(qo_len, cta_tile_q);
1048	      for (int qo_tile_idx = num_qo_tiles - 1; qo_tile_idx >= 0; --qo_tile_idx) {
1049	        auto [cta_idx, accum_cost] = cta_cost_heap.pop();
1050	        // NOTE(Zihao): our current FA3 implementation do not fuse query and group heads
1051	        // so the group_size in cost_function is always 1
1052	        int effective_kv_len =
1053	            causal ? packed_causal_kv_end(qo_len, kv_len, qo_tile_idx, cta_tile_q, num_qo_tiles, 1)
1054	                   : kv_len;
1055	        cta_cost_heap.insert({cta_idx, accum_cost + cost_function(cta_tile_q, effective_kv_len)});
1056	        cta_qo_tile_indices[cta_idx].push_back(qo_tile_idx);
1057	        cta_qo_indptr[cta_idx].push_back(qo_indptr_h[i]);
1058	        cta_qo_len[cta_idx].push_back(qo_len);
1059	        cta_kv_indptr[cta_idx].push_back(kv_indptr_h[i]);
1060	        cta_kv_len[cta_idx].push_back(kv_len);
1061	        cta_head_indices[cta_idx].push_back(qo_head_idx);
1062	        cta_batch_indices[cta_idx].push_back(i);
1063	      }
1064	    }
1065	  }
1066	
1067	  std::vector<IdType> work_indptr_vec(num_sm90_ctas + 1, 0);
1068	  for (uint32_t i = 0; i < num_sm90_ctas; ++i) {
1069	    work_indptr_vec[i + 1] = work_indptr_vec[i] + cta_qo_tile_indices[i].size();
1070	  }
1071	  int total_num_works = work_indptr_vec.back();
1072	  auto qo_tile_indices_vec = flatten(cta_qo_tile_indices, total_num_works);
1073	  auto qo_indptr_vec = flatten(cta_qo_indptr, total_num_works);
1074	  auto kv_indptr_vec = flatten(cta_kv_indptr, total_num_works);
1075	  auto qo_len_vec = flatten(cta_qo_len, total_num_works);
1076	  auto kv_len_vec = flatten(cta_kv_len, total_num_works);
1077	  auto head_indices_vec = flatten(cta_head_indices, total_num_works);
1078	  auto batch_indices_vec = flatten(cta_batch_indices, total_num_works);
1079	
1080	  AlignedAllocator int_allocator(int_buffer, int_workspace_size_in_bytes);
1081	  int max_total_num_works;
1082	
1083	  if (enable_cuda_graph) {
1084	    max_total_num_works = plan_info.same_schedule_for_all_heads
1085	                              ? max_num_works_per_head
1086	                              : max_num_works_per_head * num_qo_heads;
1087	  } else {
1088	    max_total_num_works = total_num_works;
1089	  }
1090	
1091	  plan_info.qo_tile_indices_offset = int_allocator.aligned_alloc_offset(
1092	      sizeof(IdType) * max_total_num_works, 16, "batch_prefill_sm90_qo_tile_indices");
1093	  plan_info.qo_indptr_offset = int_allocator.aligned_alloc_offset(
1094	      sizeof(IdType) * max_total_num_works, 16, "batch_prefill_sm90_qo_offset");
1095	  plan_info.kv_indptr_offset = int_allocator.aligned_alloc_offset(
1096	      sizeof(IdType) * max_total_num_works, 16, "batch_prefill_sm90_kv_offset");
1097	  plan_info.qo_len_offset = int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works,
1098	                                                               16, "batch_prefill_sm90_qo_len");
1099	  plan_info.kv_len_offset = int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works,
1100	                                                               16, "batch_prefill_sm90_kv_len");
1101	  plan_info.head_indices_offset = int_allocator.aligned_alloc_offset(
1102	      sizeof(IdType) * max_total_num_works, 16, "batch_prefill_sm90_head_indices");
1103	  plan_info.work_indptr_offset = int_allocator.aligned_alloc_offset(
1104	      sizeof(IdType) * (num_sm90_ctas + 1), 16, "batch_prefill_sm90_work_indptr");
1105	  plan_info.batch_indices_offset = int_allocator.aligned_alloc_offset(
1106	      sizeof(IdType) * max_total_num_works, 16, "batch_prefill_sm90_batch_indices");
1107	
1108	  IdType* qo_tile_indices_h =
1109	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.qo_tile_indices_offset);
1110	  IdType* qo_offset_h =
1111	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.qo_indptr_offset);
1112	  IdType* kv_offset_h =
1113	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_indptr_offset);
1114	  IdType* qo_len_h = GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.qo_len_offset);
1115	  IdType* kv_len_h = GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_len_offset);
1116	  IdType* head_indices_h =
1117	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.head_indices_offset);
1118	  IdType* work_indptr_h =
1119	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.work_indptr_offset);
1120	  IdType* batch_indices_h =
1121	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.batch_indices_offset);
1122	
1123	  std::copy(qo_tile_indices_vec.begin(), qo_tile_indices_vec.end(), qo_tile_indices_h);
1124	  std::copy(qo_indptr_vec.begin(), qo_indptr_vec.end(), qo_offset_h);
1125	  std::copy(kv_indptr_vec.begin(), kv_indptr_vec.end(), kv_offset_h);
1126	  std::copy(qo_len_vec.begin(), qo_len_vec.end(), qo_len_h);
1127	  std::copy(kv_len_vec.begin(), kv_len_vec.end(), kv_len_h);
1128	  std::copy(head_indices_vec.begin(), head_indices_vec.end(), head_indices_h);
1129	  std::copy(work_indptr_vec.begin(), work_indptr_vec.end(), work_indptr_h);
1130	  std::copy(batch_indices_vec.begin(), batch_indices_vec.end(), batch_indices_h);
1131	
1132	  size_t num_bytes_to_copy = int_allocator.num_allocated_bytes();
1133	  FLASHINFER_CUDA_CALL(cudaMemcpyAsync(int_buffer, page_locked_int_buffer, num_bytes_to_copy,
1134	                                       cudaMemcpyHostToDevice, stream));
1135	  return cudaSuccess;
1136	}
