1219	template <typename IdType>
1220	inline cudaError_t TwoStageHolisticPlan(void* float_buffer, size_t float_workspace_size_in_bytes,
1221	                                        void* int_buffer, void* page_locked_int_buffer,
1222	                                        size_t int_workspace_size_in_bytes,
1223	                                        HolisticPlanInfo<2>& plan_info, IdType* qo_indptr_h,
1224	                                        IdType* kv_indptr_h, IdType* kv_len_arr_h,
1225	                                        uint32_t batch_size, uint32_t num_qo_heads,
1226	                                        uint32_t num_kv_heads, uint32_t head_dim, bool causal,
1227	                                        cudaStream_t stream) {
1228	  constexpr uint32_t NUM_TASKS = 2;
1229	  const uint32_t CTA_TILE_Q_SIZES[NUM_TASKS] = {128, 16};
1230	  int num_sm = 0;
1231	  int dev_id = 0;
1232	
1233	  uint32_t gqa_group_size = num_qo_heads / num_kv_heads;
1234	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
1235	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
1236	
1237	  if (head_dim >= 256) {
1238	    // NOTE (Yilong): optimize this code path
1239	    // constraint gridDim due to cooperative group
1240	    num_sm *= 1;
1241	  } else {
1242	    // NOTE(Zihao): two cta per sm
1243	    num_sm *= 2;
1244	  }
1245	
1246	  // step 0. determine the number of blocks in x and y dimensions
1247	  std::vector<std::tuple<int, int, int>> idx_qo_kv_len_vec[NUM_TASKS];
1248	  for (uint32_t i = 0; i < batch_size; ++i) {
1249	    if (qo_indptr_h[i + 1] - qo_indptr_h[i] < 0) {
1250	      std::ostringstream err_msg;
1251	      err_msg << "qo_indptr[" << i + 1 << "]" << qo_indptr_h[i + 1] << " - qo_indptr[" << i << "]"
1252	              << qo_indptr_h[i] << " should be non-negative";
1253	      FLASHINFER_ERROR(err_msg.str());
1254	    }
1255	
1256	    int qo_len = qo_indptr_h[i + 1] - qo_indptr_h[i];
1257	    int packed_qo_len = qo_len * gqa_group_size;
1258	    int kv_len = kv_len_arr_h[i];
1259	
1260	    if (packed_qo_len > CTA_TILE_Q_SIZES[1]) {
1261	      idx_qo_kv_len_vec[0].push_back({i, qo_len, kv_len});
1262	    } else {
1263	      idx_qo_kv_len_vec[1].push_back({i, qo_len, kv_len});
1264	    }
1265	  }
1266	
1267	  int cluster_size = 1;
1268	  int num_clusters = num_sm / cluster_size;
1269	  plan_info.num_blks_x = cluster_size;
1270	  plan_info.num_blks_y = num_clusters;
1271	
1272	  auto f = [](int x) {
1273	    if (x <= 128) {
1274	      // This aligns with CTA_TILE_KV in persistent mainloop
1275	      // NOTE (Yilong): Optimize here for smaller batch/seqlen scenarios
1276	      return 128;
1277	    }
1278	    return ceil_div(x, 256) * 256;
1279	  };
1280	
1281	  MinHeap cluster_cost_heap(num_clusters);
1282	  AlignedAllocator int_allocator(int_buffer, int_workspace_size_in_bytes);
1283	
1284	  // NOTE(Zihao): adjust it later
1285	  const int max_total_num_works = 65536;
1286	  const int max_num_kv_splits =
1287	      4 * num_clusters * cluster_size * (CTA_TILE_Q_SIZES[0] + CTA_TILE_Q_SIZES[1]);
1288	
1289	  // calculate kv_len_limit first, considering all workloads
1290	  int64_t total_kv_lens = 0;
1291	  for (uint32_t task = 0; task < NUM_TASKS; ++task) {
1292	    int cluster_tile_q = CTA_TILE_Q_SIZES[task] * cluster_size;
1293	    for (auto& [_, qo_len, kv_len] : idx_qo_kv_len_vec[task]) {
1294	      int packed_qo_len = qo_len * gqa_group_size;
1295	      int num_qo_tiles = ceil_div(packed_qo_len, cluster_tile_q);
1296	      for (int qo_tile_idx = num_qo_tiles - 1; qo_tile_idx >= 0; --qo_tile_idx) {
1297	        int effective_kv_len =
1298	            causal ? packed_causal_kv_end(qo_len, kv_len, qo_tile_idx, cluster_tile_q, num_qo_tiles,
1299	                                          gqa_group_size)
1300	                   : kv_len;
1301	        total_kv_lens += effective_kv_len;
1302	      }
1303	    }
1304	  }
1305	
1306	  // used for remapping the output offsets
1307	  // layout [packed_qo_len x num_kv_tiles, num_kv_heads, head_dim]
1308	  int partial_o_nnz = 0;
1309	  std::vector<IdType> merge_indptr, merge_o_indices, num_expand_qo_len_vec;
1310	  std::vector<IdType> cluster_len_kv_chunk(NUM_TASKS, 0);
1311	  merge_indptr.push_back(partial_o_nnz);
1312	  for (uint32_t task = 0; task < NUM_TASKS; ++task) {
1313	    int cluster_tile_q = CTA_TILE_Q_SIZES[task] * cluster_size;
1314	    int kv_len_limit = f(std::max(ceil_div(total_kv_lens * num_kv_heads, num_clusters), 1L));
1315	    if (cluster_tile_q >= 64) {
1316	      // chunked-prefill workloads are much more expensive than decode
1317	      // so we use a smaller kv_len_limit for chunked-prefill workloads
1318	      kv_len_limit /= std::min(num_kv_heads, 2U);
1319	    }
1320	    cluster_len_kv_chunk[task] = kv_len_limit;
1321	    std::vector<std::vector<IdType>> cluster_q_indptr(num_clusters, std::vector<IdType>()),
1322	        cluster_kv_indptr(num_clusters, std::vector<IdType>()),
1323	        cluster_q_len(num_clusters, std::vector<IdType>()),
1324	        cluster_kv_len(num_clusters, std::vector<IdType>()),
1325	        cluster_q_start(num_clusters, std::vector<IdType>()),
1326	        cluster_kv_start(num_clusters, std::vector<IdType>()),
1327	        cluster_kv_end(num_clusters, std::vector<IdType>()),
1328	        cluster_kv_head_idx(num_clusters, std::vector<IdType>()),
1329	        cluster_partial_indptr(num_clusters, std::vector<IdType>());
1330	
1331	    for (auto& [i, qo_len, kv_len] : idx_qo_kv_len_vec[task]) {
1332	      int packed_qo_len = qo_len * gqa_group_size;
1333	      int num_qo_tiles = ceil_div(packed_qo_len, cluster_tile_q);
1334	      // NOTE (Yilong): this ordering correspoinds to the layout of reduction kernel
1335	      for (int qo_tile_idx = 0; qo_tile_idx < num_qo_tiles; ++qo_tile_idx) {
1336	        int remaining_len = causal
1337	                                ? packed_causal_kv_end(qo_len, kv_len, qo_tile_idx, cluster_tile_q,
1338	                                                       num_qo_tiles, gqa_group_size)
1339	                                : kv_len;
1340	        int kv_start = 0;
1341	        bool split_kv = remaining_len > kv_len_limit;
1342	        int num_kv_tiles = split_kv ? ceil_div(remaining_len, kv_len_limit) : 1;
1343	        int row_tile_size = std::min(cluster_tile_q, packed_qo_len - qo_tile_idx * cluster_tile_q);
1344	        bool zero_kv_len = (remaining_len == 0);
1345	        while (remaining_len > 0 || zero_kv_len) {
1346	          int actual_len = std::min(remaining_len, kv_len_limit);
1347	          for (uint32_t kv_head_idx = 0; kv_head_idx < num_kv_heads; ++kv_head_idx) {
1348	            auto [cluster_idx, accum_cost] = cluster_cost_heap.pop();
1349	            cluster_cost_heap.insert(
1350	                {cluster_idx, accum_cost + cost_function(cluster_tile_q, actual_len)});
1351	            cluster_q_len[cluster_idx].push_back(qo_len);
1352	            cluster_kv_len[cluster_idx].push_back(kv_len);
1353	            cluster_q_indptr[cluster_idx].push_back(qo_indptr_h[i]);
1354	            cluster_kv_indptr[cluster_idx].push_back(kv_indptr_h[i]);
1355	
1356	            // use kv_chunk to rematerize num_kv_tiles and kv_tile_idx
1357	            cluster_partial_indptr[cluster_idx].push_back(partial_o_nnz);
1358	
1359	            cluster_q_start[cluster_idx].push_back(qo_tile_idx * cluster_tile_q);
1360	            cluster_kv_start[cluster_idx].push_back(kv_start);
1361	            cluster_kv_end[cluster_idx].push_back(kv_start + actual_len);
1362	            cluster_kv_head_idx[cluster_idx].push_back(kv_head_idx);
1363	          }
1364	          remaining_len -= actual_len;
1365	          zero_kv_len = (remaining_len == 0);
1366	          kv_start += actual_len;
1367	          if (zero_kv_len) {
1368	            break;
1369	          }
1370	        }
1371	        if (split_kv) {
1372	          // non-split kv is directly written through
1373	          for (int row = 0; row < row_tile_size; ++row) {
1374	            merge_indptr.push_back(merge_indptr.back() + num_kv_tiles);
1375	            // output layout: [qo_len, num_kv_heads, gqa_group_size, head_dim]
1376	            // merge_o_indices is the indices of `gqa_group_size` dimension
1377	            auto q = (qo_tile_idx * cluster_tile_q + row) / gqa_group_size,
1378	                 r = (qo_tile_idx * cluster_tile_q + row) % gqa_group_size;
1379	            merge_o_indices.push_back((qo_indptr_h[i] + q) * num_kv_heads * gqa_group_size + r);
1380	          }
1381	          partial_o_nnz += row_tile_size * num_kv_tiles;
1382	        }
1383	      }
1384	    }
1385	
1386	    std::vector<IdType> work_indptr_vec(num_clusters + 1, 0);
1387	    for (uint32_t i = 0; i < num_clusters; ++i) {
1388	      work_indptr_vec[i + 1] = work_indptr_vec[i] + cluster_q_indptr[i].size();
1389	    }
1390	    int total_num_works = work_indptr_vec.back();
1391	    if (total_num_works > max_total_num_works) {
1392	      std::ostringstream err_msg;
1393	      err_msg << "total_num_works (#q tiles * #kv tiles) " << total_num_works
1394	              << " exceeds max_total_num_works " << max_total_num_works;
1395	      FLASHINFER_ERROR(err_msg.str());
1396	    }
1397	    auto q_indptr_vec = flatten(cluster_q_indptr, total_num_works);
1398	    auto kv_indptr_vec = flatten(cluster_kv_indptr, total_num_works);
1399	    auto partial_indptr_vec = flatten(cluster_partial_indptr, total_num_works);
1400	    auto q_len_vec = flatten(cluster_q_len, total_num_works);
1401	    auto kv_len_vec = flatten(cluster_kv_len, total_num_works);
1402	    auto q_start_vec = flatten(cluster_q_start, total_num_works);
1403	    auto kv_start_vec = flatten(cluster_kv_start, total_num_works);
1404	    auto kv_end_vec = flatten(cluster_kv_end, total_num_works);
1405	    auto kv_head_idx_vec = flatten(cluster_kv_head_idx, total_num_works);
1406	
1407	    plan_info.tasks[task].q_indptr_offset =
1408	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "q_indptr");
1409	    plan_info.tasks[task].kv_indptr_offset =
1410	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "kv_indptr");
1411	    plan_info.tasks[task].partial_indptr_offset = int_allocator.aligned_alloc_offset(
1412	        sizeof(IdType) * max_total_num_works, 16, "partial_indptr");
1413	    plan_info.tasks[task].q_len_offset =
1414	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "q_len");
1415	    plan_info.tasks[task].kv_len_offset =
1416	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "kv_len");
1417	    plan_info.tasks[task].q_start_offset =
1418	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "q_start");
1419	    plan_info.tasks[task].kv_start_offset =
1420	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "kv_start");
1421	    plan_info.tasks[task].kv_end_offset =
1422	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "kv_end");
1423	    plan_info.tasks[task].kv_head_idx_offset =
1424	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "kv_head_idx");
1425	    plan_info.tasks[task].work_indptr_offset =
1426	        int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "work_indptr");
1427	
1428	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].q_indptr_offset,
1429	                           q_indptr_vec);
1430	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].kv_indptr_offset,
1431	                           kv_indptr_vec);
1432	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].partial_indptr_offset,
1433	                           partial_indptr_vec);
1434	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].q_len_offset, q_len_vec);
1435	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].kv_len_offset, kv_len_vec);
1436	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].q_start_offset,
1437	                           q_start_vec);
1438	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].kv_start_offset,
1439	                           kv_start_vec);
1440	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].kv_end_offset, kv_end_vec);
1441	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].kv_head_idx_offset,
1442	                           kv_head_idx_vec);
1443	    CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.tasks[task].work_indptr_offset,
1444	                           work_indptr_vec);
1445	  }
1446	  plan_info.len_kv_chunk_offset =
1447	      int_allocator.aligned_alloc_offset(sizeof(IdType) * NUM_TASKS, 16, "len_kv_chunk");
1448	  CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.len_kv_chunk_offset,
1449	                         cluster_len_kv_chunk);
1450	
1451	  if (merge_indptr.size() > max_num_kv_splits) {
1452	    std::ostringstream err_msg;
1453	    err_msg << "Number of kv splits " << merge_indptr.size() << " exceeds max buffer size "
1454	            << max_num_kv_splits << ". Please increase the threshold.";
1455	    FLASHINFER_ERROR(err_msg.str());
1456	  }
1457	
1458	  // update num_qo_len_vec
1459	  num_expand_qo_len_vec.push_back(merge_indptr.size() - 1);
1460	  // allocate buffer for state merge function
1461	  plan_info.merge_indptr_offset =
1462	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_num_kv_splits, 16, "merge_indptr");
1463	  plan_info.merge_o_indices_offset =
1464	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_num_kv_splits, 16, "merge_o_indices");
1465	  plan_info.num_qo_len_offset =
1466	      int_allocator.aligned_alloc_offset(sizeof(IdType), 16, "num_qo_len_offset");
1467	  // copy data to paged cpu buffer
1468	  CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.merge_indptr_offset, merge_indptr);
1469	  CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.merge_o_indices_offset, merge_o_indices);
1470	  CopyToPageLockedBuffer(page_locked_int_buffer, plan_info.num_qo_len_offset,
1471	                         num_expand_qo_len_vec);
1472	
1473	  size_t num_bytes_to_copy = int_allocator.num_allocated_bytes();
1474	  FLASHINFER_CUDA_CALL(cudaMemcpyAsync(int_buffer, page_locked_int_buffer, num_bytes_to_copy,
1475	                                       cudaMemcpyHostToDevice, stream));
1476	  constexpr size_t sizeof_dtype_o = 2;  // NOTE (Yilong): assume fp16
1477	
1478	  // Note(Yilong): times num_kv_heads as it is not counted in partial_o_nnz
1479	  AlignedAllocator float_allocator(float_buffer, float_workspace_size_in_bytes);
1480	  plan_info.partial_o_offset = float_allocator.aligned_alloc_offset(
1481	      max_num_kv_splits * sizeof_dtype_o * head_dim * num_kv_heads, 16, "holistic_partial_o");
1482	  plan_info.partial_lse_offset = float_allocator.aligned_alloc_offset(
1483	      max_num_kv_splits * sizeof(float) * num_kv_heads, 16, "holistic_partial_lse");
1484	
1485	  return cudaSuccess;
1486	}
