1556	template <typename IdType>
1557	inline cudaError_t MLAPlan(void* float_buffer, size_t float_workspace_size_in_bytes,
1558	                           void* int_buffer, void* page_locked_int_buffer,
1559	                           size_t int_workspace_size_in_bytes, MLAPlanInfo& plan_info,
1560	                           IdType* qo_indptr_h, IdType* kv_indptr_h, IdType* kv_len_arr_h,
1561	                           uint32_t batch_size, uint32_t num_heads, uint32_t head_dim_o,
1562	                           bool causal, cudaStream_t stream) {
1563	  int num_sm = 0;
1564	  int dev_id = 0;
1565	  FLASHINFER_CUDA_CALL(cudaGetDevice(&dev_id));
1566	  FLASHINFER_CUDA_CALL(cudaDeviceGetAttribute(&num_sm, cudaDevAttrMultiProcessorCount, dev_id));
1567	
1568	  // step 0. determine the number of blocks in x and y dimensions
1569	  int accum_packed_qo_len = 0;
1570	  std::vector<std::tuple<int, int, int>> idx_qo_kv_len_vec;
1571	  for (uint32_t i = 0; i < batch_size; ++i) {
1572	    if (qo_indptr_h[i + 1] - qo_indptr_h[i] < 0) {
1573	      std::ostringstream err_msg;
1574	      err_msg << "qo_indptr[" << i + 1 << "]" << qo_indptr_h[i + 1] << " - qo_indptr[" << i << "]"
1575	              << qo_indptr_h[i] << " should be non-negative";
1576	      FLASHINFER_ERROR(err_msg.str());
1577	    }
1578	
1579	    int qo_len = qo_indptr_h[i + 1] - qo_indptr_h[i];
1580	    int packed_qo_len = qo_len * num_heads;
1581	    accum_packed_qo_len += packed_qo_len;
1582	
1583	    int kv_len = kv_len_arr_h[i];
1584	    idx_qo_kv_len_vec.push_back({i, qo_len, kv_len});
1585	  }
1586	  int avg_packed_qo_len = accum_packed_qo_len / batch_size;
1587	
1588	  int cluster_size;
1589	  if (avg_packed_qo_len > 64) {
1590	    cluster_size = 2;  // two ctas in a cluster
1591	  } else {
1592	    cluster_size = 1;  // one cta in a cluster
1593	  }
1594	  uint32_t num_clusters = num_sm / cluster_size;
1595	  plan_info.num_blks_x = cluster_size;
1596	  plan_info.num_blks_y = num_clusters;
1597	  const int cta_tile_q = 64;
1598	  int cluster_tile_q = cluster_size * cta_tile_q;
1599	
1600	  int64_t total_kv_lens = 0;
1601	  for (auto& [_, qo_len, kv_len] : idx_qo_kv_len_vec) {
1602	    int packed_qo_len = qo_len * num_heads;
1603	    int num_qo_tiles = ceil_div(packed_qo_len, cluster_tile_q);
1604	    for (int qo_tile_idx = num_qo_tiles - 1; qo_tile_idx >= 0; --qo_tile_idx) {
1605	      int effective_kv_len = causal ? packed_causal_kv_end(qo_len, kv_len, qo_tile_idx,
1606	                                                           cluster_tile_q, num_qo_tiles, num_heads)
1607	                                    : kv_len;
1608	      total_kv_lens += effective_kv_len;
1609	    }
1610	  }
1611	
1612	  auto f = [](int x) {
1613	    if (x <= 8) {
1614	      return 32;
1615	    } else if (x <= 16) {
1616	      return 64;
1617	    } else if (x <= 32) {
1618	      return 128;
1619	    } else if (x <= 64) {
1620	      return 192;
1621	    }
1622	    return ceil_div(x, 256) * 256;
1623	  };
1624	
1625	  int kv_len_limit = f(std::max(ceil_div(total_kv_lens, num_clusters), 1L));
1626	
1627	  // step 1. load-balancing scheduling algorithm
1628	  MinHeap cluster_cost_heap(num_clusters);
1629	  std::vector<std::vector<IdType>> cluster_q_indptr(num_clusters, std::vector<IdType>()),
1630	      cluster_kv_indptr(num_clusters, std::vector<IdType>()),
1631	      cluster_q_len(num_clusters, std::vector<IdType>()),
1632	      cluster_kv_len(num_clusters, std::vector<IdType>()),
1633	      cluster_q_start(num_clusters, std::vector<IdType>()),
1634	      cluster_kv_start(num_clusters, std::vector<IdType>()),
1635	      cluster_kv_end(num_clusters, std::vector<IdType>()),
1636	      cluster_partial_indptr(num_clusters, std::vector<IdType>());
1637	
1638	  std::vector<IdType> merge_packed_offset_start(num_sm, 0), merge_packed_offset_end(num_sm, 0),
1639	      merge_partial_packed_offset_start(num_sm, 0), merge_partial_packed_offset_end(num_sm, 0),
1640	      merge_partial_stride(num_sm, 0);
1641	
1642	  int merge_cta_counter = 0;
1643	  int partial_o_nnz = 0;
1644	
1645	  for (auto& [i, qo_len, kv_len] : idx_qo_kv_len_vec) {
1646	    int packed_qo_len = qo_len * num_heads;
1647	    int num_qo_tiles = ceil_div(packed_qo_len, cluster_tile_q);
1648	    for (int qo_tile_idx = num_qo_tiles - 1; qo_tile_idx >= 0; --qo_tile_idx) {
1649	      int remaining_len = causal ? packed_causal_kv_end(qo_len, kv_len, qo_tile_idx, cluster_tile_q,
1650	                                                        num_qo_tiles, num_heads)
1651	                                 : kv_len;
1652	      int kv_start = 0;
1653	      bool split_kv = remaining_len > kv_len_limit;
1654	      int row_tile_size = std::min(cluster_tile_q, packed_qo_len - qo_tile_idx * cluster_tile_q);
1655	      if (split_kv) {
1656	        /*
1657	         * Proof(Zihao): merge_cta_counter <= num_sm (num_sm == num_clusters * cluster_size)
1658	         *
1659	         * Precondition:
1660	         * 1. kv_len_limit * num_clusters >= total_kv_lens == sum(remaining_len)
1661	         * 2. num_qo_chunks <= max((remaining_len * cluster_size) // kv_len_limit, 1)
1662	         * 3. num_qo_tiles_requires_split <= num_clusters
1663	
1664	         * Implication:
1665	         * 1. sum(num_qo_chunks) <= max(sum(remaining_len) * cluster_size / kv_len_limit,
1666	         num_qo_tiles_requires_split)
1667	         * 2. sum(num_qo_chunks) <= max(cluster_size * num_clusters, num_qo_tiles_requires_split)
1668	         */
1669	        int num_qo_chunks = std::max(remaining_len * cluster_size / kv_len_limit, 1);
1670	        // row_chunk_size * num_qo_chunks >= row_tile_size
1671	        int row_chunk_size = ceil_div(row_tile_size, num_qo_chunks);
1672	        int current_q_tile_end =
1673	            std::min(cluster_tile_q, packed_qo_len - qo_tile_idx * cluster_tile_q);
1674	        for (int offset_start = 0; offset_start < row_tile_size; offset_start += row_chunk_size) {
1675	          merge_packed_offset_start[merge_cta_counter] =
1676	              qo_indptr_h[i] * num_heads + qo_tile_idx * cluster_tile_q + offset_start;
1677	          merge_packed_offset_end[merge_cta_counter] =
1678	              qo_indptr_h[i] * num_heads + qo_tile_idx * cluster_tile_q +
1679	              std::min(offset_start + row_chunk_size, current_q_tile_end);
1680	          merge_partial_packed_offset_start[merge_cta_counter] = partial_o_nnz + offset_start;
1681	          merge_partial_packed_offset_end[merge_cta_counter] =
1682	              partial_o_nnz + ceil_div(remaining_len, kv_len_limit) * row_tile_size;
1683	          merge_partial_stride[merge_cta_counter] = row_tile_size;
1684	          merge_cta_counter++;
1685	        }
1686	      }
1687	      bool zero_kv_len = (remaining_len == 0);
1688	      while (remaining_len > 0 || zero_kv_len) {
1689	        auto [cluster_idx, accum_cost] = cluster_cost_heap.pop();
1690	        int actual_len = std::min(remaining_len, kv_len_limit);
1691	        cluster_cost_heap.insert(
1692	            {cluster_idx, accum_cost + cost_function(cluster_tile_q, actual_len)});
1693	        cluster_q_len[cluster_idx].push_back(qo_len);
1694	        cluster_kv_len[cluster_idx].push_back(kv_len);
1695	        cluster_q_indptr[cluster_idx].push_back(qo_indptr_h[i]);
1696	        cluster_kv_indptr[cluster_idx].push_back(kv_indptr_h[i]);
1697	        if (split_kv) {
1698	          cluster_partial_indptr[cluster_idx].push_back(partial_o_nnz);
1699	          partial_o_nnz += row_tile_size;
1700	        } else {
1701	          cluster_partial_indptr[cluster_idx].push_back(-1);
1702	        }
1703	        cluster_q_start[cluster_idx].push_back(qo_tile_idx * cluster_tile_q);
1704	        cluster_kv_start[cluster_idx].push_back(kv_start);
1705	        cluster_kv_end[cluster_idx].push_back(kv_start + actual_len);
1706	        remaining_len -= actual_len;
1707	        kv_start += actual_len;
1708	        if (zero_kv_len) break;
1709	      }
1710	    }
1711	  }
1712	
1713	  FLASHINFER_CHECK(merge_cta_counter <= num_sm,
1714	                   "Internal Error: merge_cta_counter should be less than or equal to num_sm, "
1715	                   "please report this bug to the developers");
1716	
1717	  int max_total_num_works = 16384;  // NOTE(Zihao): adjust it later
1718	
1719	  std::vector<IdType> work_indptr_vec(num_clusters + 1, 0);
1720	  for (uint32_t i = 0; i < num_clusters; ++i) {
1721	    work_indptr_vec[i + 1] = work_indptr_vec[i] + cluster_q_indptr[i].size();
1722	  }
1723	  int total_num_works = work_indptr_vec.back();
1724	  auto q_indptr_vec = flatten(cluster_q_indptr, total_num_works);
1725	  auto kv_indptr_vec = flatten(cluster_kv_indptr, total_num_works);
1726	  auto partial_indptr_vec = flatten(cluster_partial_indptr, total_num_works);
1727	  auto q_len_vec = flatten(cluster_q_len, total_num_works);
1728	  auto kv_len_vec = flatten(cluster_kv_len, total_num_works);
1729	  auto q_start_vec = flatten(cluster_q_start, total_num_works);
1730	  auto kv_start_vec = flatten(cluster_kv_start, total_num_works);
1731	  auto kv_end_vec = flatten(cluster_kv_end, total_num_works);
1732	
1733	  AlignedAllocator int_allocator(int_buffer, int_workspace_size_in_bytes);
1734	  plan_info.q_indptr_offset =
1735	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "mla_q_indptr");
1736	  plan_info.kv_indptr_offset =
1737	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "mla_kv_indptr");
1738	  plan_info.partial_indptr_offset = int_allocator.aligned_alloc_offset(
1739	      sizeof(IdType) * max_total_num_works, 16, "mla_partial_indptr");
1740	  plan_info.merge_packed_offset_start_offset = int_allocator.aligned_alloc_offset(
1741	      sizeof(IdType) * num_sm, 16, "mla_merge_packed_offset_start");
1742	  plan_info.merge_packed_offset_end_offset = int_allocator.aligned_alloc_offset(
1743	      sizeof(IdType) * num_sm, 16, "mla_merge_packed_offset_end");
1744	  plan_info.merge_partial_packed_offset_start_offset = int_allocator.aligned_alloc_offset(
1745	      sizeof(IdType) * num_sm, 16, "mla_merge_partial_packed_offset_start");
1746	  plan_info.merge_partial_packed_offset_end_offset = int_allocator.aligned_alloc_offset(
1747	      sizeof(IdType) * num_sm, 16, "mla_merge_partial_packed_offset_end");
1748	  plan_info.merge_partial_stride_offset =
1749	      int_allocator.aligned_alloc_offset(sizeof(IdType) * num_sm, 16, "mla_merge_partial_stride");
1750	  plan_info.q_len_offset =
1751	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "mla_q_len");
1752	  plan_info.kv_len_offset =
1753	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "mla_kv_len");
1754	  plan_info.q_start_offset =
1755	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "mla_q_start");
1756	  plan_info.kv_start_offset =
1757	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "mla_kv_start");
1758	  plan_info.kv_end_offset =
1759	      int_allocator.aligned_alloc_offset(sizeof(IdType) * max_total_num_works, 16, "mla_kv_end");
1760	  plan_info.work_indptr_offset = int_allocator.aligned_alloc_offset(
1761	      sizeof(IdType) * max_total_num_works, 16, "mla_work_indptr");
1762	
1763	  IdType* cluster_q_indptr_h =
1764	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.q_indptr_offset);
1765	  IdType* cluster_kv_indptr_h =
1766	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_indptr_offset);
1767	  IdType* cluster_partial_indptr_h =
1768	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.partial_indptr_offset);
1769	  IdType* cluster_merge_packed_offset_start_h = GetPtrFromBaseOffset<IdType>(
1770	      page_locked_int_buffer, plan_info.merge_packed_offset_start_offset);
1771	  IdType* cluster_merge_packed_offset_end_h = GetPtrFromBaseOffset<IdType>(
1772	      page_locked_int_buffer, plan_info.merge_packed_offset_end_offset);
1773	  IdType* cluster_merge_partial_packed_offset_start_h = GetPtrFromBaseOffset<IdType>(
1774	      page_locked_int_buffer, plan_info.merge_partial_packed_offset_start_offset);
1775	  IdType* cluster_merge_partial_packed_offset_end_h = GetPtrFromBaseOffset<IdType>(
1776	      page_locked_int_buffer, plan_info.merge_partial_packed_offset_end_offset);
1777	  IdType* cluster_merge_partial_stride_h =
1778	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.merge_partial_stride_offset);
1779	  IdType* cluster_q_len_h =
1780	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.q_len_offset);
1781	  IdType* cluster_kv_len_h =
1782	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_len_offset);
1783	  IdType* cluster_q_start_h =
1784	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.q_start_offset);
1785	  IdType* cluster_kv_start_h =
1786	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_start_offset);
1787	  IdType* cluster_kv_end_h =
1788	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.kv_end_offset);
1789	  IdType* cluster_work_indptr_h =
1790	      GetPtrFromBaseOffset<IdType>(page_locked_int_buffer, plan_info.work_indptr_offset);
1791	
1792	  std::copy(q_indptr_vec.begin(), q_indptr_vec.end(), cluster_q_indptr_h);
1793	  std::copy(kv_indptr_vec.begin(), kv_indptr_vec.end(), cluster_kv_indptr_h);
1794	  std::copy(partial_indptr_vec.begin(), partial_indptr_vec.end(), cluster_partial_indptr_h);
1795	  std::copy(merge_packed_offset_start.begin(), merge_packed_offset_start.end(),
1796	            cluster_merge_packed_offset_start_h);
1797	  std::copy(merge_packed_offset_end.begin(), merge_packed_offset_end.end(),
1798	            cluster_merge_packed_offset_end_h);
1799	  std::copy(merge_partial_packed_offset_start.begin(), merge_partial_packed_offset_start.end(),
1800	            cluster_merge_partial_packed_offset_start_h);
1801	  std::copy(merge_partial_packed_offset_end.begin(), merge_partial_packed_offset_end.end(),
1802	            cluster_merge_partial_packed_offset_end_h);
1803	  std::copy(merge_partial_stride.begin(), merge_partial_stride.end(),
1804	            cluster_merge_partial_stride_h);
1805	  std::copy(q_len_vec.begin(), q_len_vec.end(), cluster_q_len_h);
1806	  std::copy(kv_len_vec.begin(), kv_len_vec.end(), cluster_kv_len_h);
1807	  std::copy(q_start_vec.begin(), q_start_vec.end(), cluster_q_start_h);
1808	  std::copy(kv_start_vec.begin(), kv_start_vec.end(), cluster_kv_start_h);
1809	  std::copy(kv_end_vec.begin(), kv_end_vec.end(), cluster_kv_end_h);
1810	  std::copy(work_indptr_vec.begin(), work_indptr_vec.end(), cluster_work_indptr_h);
1811	
1812	  size_t num_bytes_to_copy = int_allocator.num_allocated_bytes();
1813	  FLASHINFER_CUDA_CALL(cudaMemcpyAsync(int_buffer, page_locked_int_buffer, num_bytes_to_copy,
1814	                                       cudaMemcpyHostToDevice, stream));
1815	
1816	  constexpr size_t sizeof_dtype_o = 2;
1817	  AlignedAllocator float_allocator(float_buffer, float_workspace_size_in_bytes);
1818	  plan_info.partial_o_offset = float_allocator.aligned_alloc_offset(
1819	      2 * num_clusters * cluster_tile_q * sizeof_dtype_o * head_dim_o, 16, "mla_partial_o");
1820	  plan_info.partial_lse_offset = float_allocator.aligned_alloc_offset(
1821	      2 * num_clusters * cluster_tile_q * sizeof(float), 16, "mla_partial_lse");
1822	
1823	  return cudaSuccess;
1824	}
1825	
1826	}  // namespace flashinfer
1827	#endif  // FLASHINFER_ATTENTION_SCHEDULER_CUH_
